const helpersDebug=mourn.debug.on&&mourn.debug.includeHelpers,helpersDebugV=mourn.debug.verbose&&mourn.debug.includeHelpers;function scale(n,e,t,o,r){return Number.isFinite(e)&&Number.isFinite(t)&&t!==e?(n-e)*(r-o)/(t-e)+o:.5*(o+r)}function logScale(n){const e=(mourn.staging.maxScaling-mourn.staging.minScaling)/Math.log(10);return Math.log(n)*e+mourn.staging.minScaling}function invLogScale(n){return scale(logScale(n),mourn.staging.minScaling,mourn.staging.maxScaling,mourn.staging.maxScaling,mourn.staging.minScaling)}function getRandomInt(n){return Math.floor(Math.random()*n)}function randomStanzaIndex(){return getRandomInt(mourn.config.stanzaCount)}function getAutoScrollSpeedFromURL(){const n=new URLSearchParams(window.location.search).get("auto");if(null===n)return null;const e=parseFloat(n);return Number.isFinite(e)?e:(console.warn("Invalid auto-scroll speed. Expected float for `auto` URL parameter."),null)}function fetchStanza(n,e,t=null){const o=mourn.config.stanzaCount,r=e+' [data-stanza-number="'+(n%o+o)%o+'"]';let i="";null!==t&&(i='[uid="'+t+'"]');return document.querySelector(r+i)}function fetchStagedStanza(n){return fetchStanza(n,"#poem-staging")}function fetchRenderedStanza(n,e){return fetchStanza(n,"#poem-container",e)}function isInViewport(n){helpersDebug&&console.log("++--is in viewport--++");const e=mourn.scrollZoneData.lenience;var t=n.getBoundingClientRect(),o=document.documentElement;return t.top>=0-e&&t.left>=0-e&&t.bottom<=(window.innerHeight||o.clientHeight)+e&&t.right<=(window.innerWidth||o.clientWidth)+e}function getUID(n){if(null!==n.getAttribute("uid"))return n.getAttribute("uid");console.error("________________________"),console.log(n),console.error("Above stanza has no UID.")}function fetchConnector(n,e){return e<0?n.querySelector(".initiator"):e>0?n.querySelector(".terminator"):void console.error("Improper direction declared.")}function checkForVisibleConnectors(){const n=Object.keys(mourn.trackers.nonRenderedConnectors);if(n.length>0){const e=[];return n.forEach((n=>{isInViewport(mourn.trackers.nonRenderedConnectors[n].stanza)&&e.push(n)})),e}return[]}function UID(){return Date.now().toString(36)+Math.random().toString(36).substring(2,12).padStart(12,0)}function lineSlope(n){return(n[1].y-n[0].y)/(n[1].x-n[0].x)}function angleFromSlopes(n,e){return Math.atan((e-n)/(1+n*e))}function waydelay(n,e){console.log("called");(async()=>{await(t=n,new Promise((n=>setTimeout(n,t))));var t;e()})()}